'use strict';

var DefinePropertyOrThrow = require('./DefinePropertyOrThrow');
var Get = require('./Get');
var OrdinaryGetOwnProperty = require('./OrdinaryGetOwnProperty');
var ToObject = require('./ToObject');
var ToPropertyDescriptor = require('./ToPropertyDescriptor');

var forEach = require('../helpers/forEach');
var OwnPropertyKeys = require('own-keys');



module.exports = function ObjectDefineProperties(O, Properties) {
	var props = ToObject(Properties); 
	var keys = OwnPropertyKeys(props); 
	var descriptors = []; 

	forEach(keys, function (nextKey) { 
		var propDesc = OrdinaryGetOwnProperty(props, nextKey); 
		if (typeof propDesc !== 'undefined' && propDesc['[[Enumerable]]']) { 
			var descObj = Get(props, nextKey); 
			var desc = ToPropertyDescriptor(descObj); 
			descriptors[descriptors.length] = { '[[Key]]': nextKey, '[[Descriptor]]': desc }; 
		}
	});

	forEach(descriptors, function (pair) { 
		DefinePropertyOrThrow(O, pair['[[Key]]'], pair['[[Descriptor]]']); 
	});

	return O; 
};
